import{_ as a,c as i,o as e,ag as t}from"./chunks/framework.D4Vqf8I7.js";const k=JSON.parse('{"title":"Альт Домен","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"docs/wi/alt-domain.md","filePath":"docs/wi/alt-domain.md","lastUpdated":1779893064000}'),l={name:"docs/wi/alt-domain.md"};function n(h,s,o,p,r,d){return e(),i("div",null,s[0]||(s[0]=[t(`<h1 id="альт-домен" tabindex="-1">Альт Домен <a class="header-anchor" href="#альт-домен" aria-label="Permalink to &quot;Альт Домен&quot;">​</a></h1><h2 id="подходы-к-миграции-доменнои-структуры" tabindex="-1">Подходы к миграции доменной структуры <a class="header-anchor" href="#подходы-к-миграции-доменнои-структуры" aria-label="Permalink to &quot;Подходы к миграции доменной структуры&quot;">​</a></h2><p>Универсального алгоритма миграции не существует. Выбор стратегии определяется результатами аудита исходной системы. Ниже приведены основные подходы, применяемые на практике.</p><h3 id="_1-развертывание-чистои-инсталляции-«альт-домен»" tabindex="-1">1. Развёртывание чистой инсталляции «Альт Домен» <a class="header-anchor" href="#_1-развертывание-чистои-инсталляции-«альт-домен»" aria-label="Permalink to &quot;1. Развёртывание чистой инсталляции «Альт Домен»&quot;">​</a></h3><ul><li>Выполняется установка нового домена на базе «Альт Домен».</li><li>Настраиваются отношения доверия (trust) с существующим доменом Microsoft Active Directory (MS AD).</li><li>Осуществляется постепенный перенос объектов (пользователей, групп, политик) из исходного домена в целевой.</li></ul><p><strong>Недостатки:</strong></p><ul><li>Требуется изменение имени домена, что может повлечь необходимость обновления конфигураций клиентских систем и приложений.</li></ul><h3 id="_2-интеграция-контроллера-домена-«альт-домен»-в-существующии-домен-ms-ad" tabindex="-1">2. Интеграция контроллера домена «Альт Домен» в существующий домен MS AD <a class="header-anchor" href="#_2-интеграция-контроллера-домена-«альт-домен»-в-существующии-домен-ms-ad" aria-label="Permalink to &quot;2. Интеграция контроллера домена «Альт Домен» в существующий домен MS AD&quot;">​</a></h3><ul><li>Контроллер домена на базе «Альт Домен» добавляется в качестве реплики в действующий домен MS AD.</li><li>После синхронизации данных выполняется вывод контроллеров MS AD из домена, перенос ролей FSMO на контроллер «Альт Домен».</li></ul><p><strong>Рекомендуемая практика:</strong></p><ol><li>Развернуть дополнительный контроллер домена на базе MS AD.</li><li>Перенести данный контроллер в изолированную тестовую сеть.</li><li>Назначить ему роли FSMO.</li><li>Добавить контроллер «Альт Домен» (на базе Samba) в качестве реплики к тестовому контроллеру.</li><li>Провести отладку процесса репликации, проверить целостность переноса данных.</li><li>После успешного тестирования выполнить миграцию в продуктивную среду с учётом накопленного опыта.</li></ol><h4 id="_2-1-импорт-базы-ms-ad-через-samba-tool" tabindex="-1">2.1. Импорт базы MS AD через samba-tool <a class="header-anchor" href="#_2-1-импорт-базы-ms-ad-через-samba-tool" aria-label="Permalink to &quot;2.1. Импорт базы MS AD через samba-tool&quot;">​</a></h4><p>В качестве альтернативы допускается прямой импорт базы данных домена MS AD в Samba с использованием механизма резервного копирования и утилиты <code>samba-tool</code>. Данный метод требует предварительного тестирования в изолированной среде.</p><h3 id="_3-миграция-с-использованием-сторонних-инструментов" tabindex="-1">3. Миграция с использованием сторонних инструментов <a class="header-anchor" href="#_3-миграция-с-использованием-сторонних-инструментов" aria-label="Permalink to &quot;3. Миграция с использованием сторонних инструментов&quot;">​</a></h3><p>Для переноса объектов домена могут применяться специализированные средства:</p><ul><li><strong>ADMT</strong> (Active Directory Migration Tool);</li><li><strong>PagmaticTools Migrator</strong> и аналогичные решения.</li></ul><p>Выбор инструмента определяется совместимостью с целевой инфраструктурой, объёмом миграционных данных и требованиями к минимизации простоев.</p><h2 id="ограничение-доступа-пользователеи-через-sssd" tabindex="-1">Ограничение доступа пользователей через SSSD <a class="header-anchor" href="#ограничение-доступа-пользователеи-через-sssd" aria-label="Permalink to &quot;Ограничение доступа пользователей через SSSD&quot;">​</a></h2><h3 id="контекст-применения" tabindex="-1">Контекст применения <a class="header-anchor" href="#контекст-применения" aria-label="Permalink to &quot;Контекст применения&quot;">​</a></h3><ul><li>Типы входа: интерактивный вход и вход по SSH.</li><li>Клиентская система введена в домен с использованием SSSD в соответствии с официальным руководством.</li><li>Активирована поддержка групповых политик.</li></ul><h3 id="настроика-фильтра-доступа-через-ldap" tabindex="-1">Настройка фильтра доступа через LDAP <a class="header-anchor" href="#настроика-фильтра-доступа-через-ldap" aria-label="Permalink to &quot;Настройка фильтра доступа через LDAP&quot;">​</a></h3><p>Для ограничения доступа пользователей на основе принадлежности к группам домена используется параметр <code>ad_access_filter</code> в конфигурационном файле <code>/etc/sssd/sssd.conf</code> (или в файлах секции <code>/etc/sssd/conf.d/</code>).</p><h4 id="пример-конфигурации" tabindex="-1">Пример конфигурации <a class="header-anchor" href="#пример-конфигурации" aria-label="Permalink to &quot;Пример конфигурации&quot;">​</a></h4><p>Исходные данные:</p><ul><li>Домен: <code>test.alt</code></li><li>Группа: <code>workers</code></li><li>Члены группы: <code>domainuser1</code>, <code>domainuser2</code></li></ul><p>Задача: разрешить доступ всем членам группы <code>workers</code>, за исключением пользователя <code>domainuser1</code>.</p><p><strong>Вариант 1: Правка основного файла конфигурации</strong></p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[domain/TEST.ALT]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ad_access_filter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = (&amp;(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">memberOf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=workers,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=Users,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DC</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=test,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DC</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=alt)(!(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">sAMAccountName</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=domainuser1)))</span></span></code></pre></div><p><strong>Вариант 2: Вынос правила в отдельный файл</strong> Файл: <code>/etc/sssd/conf.d/forbid_users.conf</code></p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[domain/TEST.ALT]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ad_access_filter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = (&amp;(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">memberOf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=workers,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=Users,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DC</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=test,</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DC</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=alt)(!(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">sAMAccountName</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=domainuser1)))</span></span></code></pre></div><p>После внесения изменений необходимо перезапустить службу SSSD:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sssd</span></span></code></pre></div><blockquote><p><strong>Важно.</strong> Синтаксис фильтра должен соответствовать стандарту LDAP. Ошибки в формулировке фильтра могут привести к блокировке легитимных пользователей.</p></blockquote><h2 id="разграничение-типов-входа-интерактивныи-вход-и-ssh" tabindex="-1">Разграничение типов входа: интерактивный вход и SSH <a class="header-anchor" href="#разграничение-типов-входа-интерактивныи-вход-и-ssh" aria-label="Permalink to &quot;Разграничение типов входа: интерактивный вход и SSH&quot;">​</a></h2><p>Для независимого управления разрешениями на интерактивный вход и вход по SSH рекомендуется использовать конфигурацию демона <code>sshd</code>.</p><h3 id="ограничение-доступа-по-группам-через-sshd-config" tabindex="-1">Ограничение доступа по группам через sshd_config <a class="header-anchor" href="#ограничение-доступа-по-группам-через-sshd-config" aria-label="Permalink to &quot;Ограничение доступа по группам через sshd_config&quot;">​</a></h3><p>Файл конфигурации: <code>/etc/openssh/sshd_config</code></p><p><strong>Использование директивы <code>AllowGroups</code>:</strong></p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">AllowGroups workers ssh-users</span></span></code></pre></div><p>Данная директива разрешает вход по SSH только пользователям, входящим в указанные группы. Все остальные пользователи будут отклонены.</p><p><strong>Гибкая настройка через <code>Match Group</code>:</strong></p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Match Group workers</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    AllowTcpForwarding yes</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    PermitTTY yes</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Match Group ssh-admins</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    PermitRootLogin yes</span></span></code></pre></div><p>Директива <code>Match</code> позволяет применять настройки условно, в зависимости от группы пользователя, что обеспечивает более тонкое управление политиками доступа.</p><h3 id="управление-настроиками-через-утилиту-control" tabindex="-1">Управление настройками через утилиту control <a class="header-anchor" href="#управление-настроиками-через-утилиту-control" aria-label="Permalink to &quot;Управление настройками через утилиту control&quot;">​</a></h3><p>В системе ALT Linux для управления сервисами и их параметрами рекомендуется использовать утилиту <code>control</code>.</p><p>Примеры команд:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">control</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sshd-allow-groups</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">control</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sshd-allow-groups-list</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">control</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ssh</span></span></code></pre></div><p>Дополнительная информация доступна по ссылке: <a href="https://www.altlinux.org/Control" target="_blank" rel="noreferrer">https://www.altlinux.org/Control</a></p>`,48)]))}const g=a(l,[["render",n]]);export{k as __pageData,g as default};
